package playReady

import (
   "encoding/hex"
   "testing"
)

func TestParsePro(t *testing.T) {
   data, err := hex.DecodeString(hexStr)
   if err != nil {
      t.Fatalf("Failed to decode hex: %v", err)
   }

   wrmHeader, err := ParsePro(data)
   if err != nil {
      t.Fatalf("Failed to parse PRO: %v", err)
   }

   // Assert base properties
   if wrmHeader.Version != "4.0.0.0" {
      t.Errorf("Expected version 4.0.0.0, got %s", wrmHeader.Version)
   }
   if wrmHeader.XmlNs != "http://schemas.microsoft.com/DRM/2007/03/PlayReadyHeader" {
      t.Errorf("Expected valid xmlns, got %s", wrmHeader.XmlNs)
   }

   // Assert Protection info
   if wrmHeader.Data.ProtectInfo.AlgId != "AESCTR" {
      t.Errorf("Expected AlgId 'AESCTR', got %s", wrmHeader.Data.ProtectInfo.AlgId)
   }
   if wrmHeader.Data.ProtectInfo.KeyLen != 16 {
      t.Errorf("Expected KeyLen 16, got %d", wrmHeader.Data.ProtectInfo.KeyLen)
   }

   // Assert Custom Attributes
   if wrmHeader.Data.CustomAttributes == nil {
      t.Fatalf("Expected CustomAttributes to not be nil")
   }
   expectedCID := "ff-41f446bd-1474247"
   if wrmHeader.Data.CustomAttributes.ContentId != expectedCID {
      t.Errorf("Expected ContentId '%s', got '%s'", expectedCID, wrmHeader.Data.CustomAttributes.ContentId)
   }

   // Validate KID (The XML unmarshaler will automatically decode the base64 KID into your byte slice)
   // Base64 in original XML: "HyqWP6q2XNu8SE32nf2pcQ=="
   expectedKidLen := 16
   if len(wrmHeader.Data.Kid) != expectedKidLen {
      t.Errorf("Expected KID length %d, got %d", expectedKidLen, len(wrmHeader.Data.Kid))
   }
}

const hexStr = ""
